SELECT r.*, u.username, e.name AS event_name FROM registration r LEFT JOIN user u ON r.user_id = u.id LEFT JOIN event e ON r.event_id = e.id WHERE 1=1
AND r.event_id = #{eventId}
AND r.status = #{status}
ORDER BY r.apply_time DESC

SELECT COUNT(*)
FROM registration
WHERE user_id = #{userId}
  AND event_id = #{eventId}
  AND status != 3
